import json, re
from collections import defaultdict

# Get business data
business_data = locals()['var_functions.query_db:20']

# Extract state from description
def extract_state(description):
    if not description:
        return None

    # Pattern for "City, ST" or "City, ST Zip"
    patterns = [r'([A-Z]{2})\s+\d{5}', r'([A-Z]{2}),']

    for pattern in patterns:
        match = re.search(pattern, description)
        if match:
            return match.group(1)

    return None

# Process all businesses
business_list = []
for biz in business_data:
    desc = biz.get('description', '')
    state = extract_state(desc)
    if state:
        business_list.append({
            'business_id': biz.get('business_id'),
            'state': state,
            'review_count': int(str(biz.get('review_count', 0)))
        })

# Sum review counts by state
state_totals = defaultdict(int)
for biz in business_list:
    state_totals[biz['state']] += biz['review_count']

# Sort by total reviews
sorted_states = sorted(state_totals.items(), key=lambda x: x[1], reverse=True)

# Find top state
if sorted_states:
    top_state_code = sorted_states[0][0]
    top_state_total = sorted_states[0][1]

    # Get business IDs for top state
    top_state_biz_ids = [biz['business_id'] for biz in business_list if biz['state'] == top_state_code]

    result = {
        'top_state': top_state_code,
        'total_reviews': top_state_total,
        'business_count': len(top_state_biz_ids),
        'business_ids': top_state_biz_ids
    }
else:
    result = {'error': 'No state data found'}

print('__RESULT__:' + json.dumps(result))

