import json, re

# Get all business data - no limit specified to get full dataset
business_data = locals()['var_functions.query_db:28']

# First, check if this is the full dataset or a file path
if isinstance(business_data, str) and business_data.startswith('/tmp/'):
    with open(business_data, 'r') as f:
        business_data = json.load(f)

print('Dataset size: ' + str(len(business_data)))

# Extract state from description using regex
def extract_state(desc):
    if not desc:
        return None

    # Look for patterns like "City, ST" or "City, ST 12345"
    patterns = [r'([A-Z]{2})\s+\d{5}', r'([A-Z]{2}),']
    for pattern in patterns:
        match = re.search(pattern, desc)
        if match:
            return match.group(1)
    return None

# Process all businesses
state_counts = {}
business_states = {}

for biz in business_data:
    desc = biz.get('description', '')
    state = extract_state(desc)
    reviews = int(str(biz.get('review_count', 0)))
    biz_id = biz.get('business_id')

    if state and reviews > 0:
        state_counts[state] = state_counts.get(state, 0) + reviews
        if state not in business_states:
            business_states[state] = []
        business_states[state].append({'id': biz_id, 'reviews': reviews})

# Sort states by total review count
top_states = sorted(state_counts.items(), key=lambda x: x[1], reverse=True)

result = {
    'dataset_size': len(business_data),
    'states_found': len(state_counts),
    'top_states': [{'state': s, 'total_reviews': c, 'business_count': len(business_states[s])} for s, c in top_states[:10]]
}

print('__RESULT__:' + json.dumps(result))

