import json, re
from collections import defaultdict

# Get business data from storage
def get_data(key):
    data = locals()[key]
    # Check if it's a file path
    if isinstance(data, str) and data.startswith('/tmp/'):
        with open(data, 'r') as f:
            return json.load(f)
    return data

biz_data = get_data('var_functions.query_db:38')

print('Dataset size: ' + str(len(biz_data)))

# Check if this is the full dataset or just a sample
if len(biz_data) <= 10:
    print('Small sample detected')
    print('Sample data: ' + str(biz_data))
else:
    print('Full dataset retrieved')

# Extract state and sum reviews
def extract_state(desc):
    if not desc: return None
    match = re.search(r'([A-Z]{2})[\s,]', desc)
    return match.group(1) if match else None

state_reviews = defaultdict(int)
biz_states = {}

for biz in biz_data:
    state = extract_state(biz.get('description', ''))
    if state:
        reviews = int(str(biz.get('review_count', 0)))
        state_reviews[state] += reviews
        biz_states[biz['business_id']] = state

# Find top state
top_state = max(state_reviews.items(), key=lambda x: x[1])

result = {
    'top_state': top_state[0],
    'total_reviews': top_state[1],
    'business_ids': {bid: state for bid, state in biz_states.items() if state == top_state[0]}
}

print('__RESULT__:' + json.dumps(result))

